SELECT 
  ABS((DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO)) VALOR,
  CASE WHEN (DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO)<0
       THEN '-'
       ELSE '+'
       END SIGNO, 
  CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='13'
       THEN ABS((DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO))
       ELSE 0
       END RECAUDOENPAPELES, 
  CASE WHEN (CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END)='15'
       THEN (DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO)*-1
       ELSE 0
       END OTRASCANCELACIONES,
  PLAN_PRESUPUESTAL.NOMBRE, 
  PLAN_PRESUPUESTAL.NIVEL1,  
  PLAN_PRESUPUESTAL.NIVEL2,    
  PLAN_PRESUPUESTAL.NIVEL3, 
  PLAN_PRESUPUESTAL.NIVEL4, 
  PLAN_PRESUPUESTAL.NIVEL5,
  DETALLE_COMPROBANTE_PPTAL.MES, 
  DETALLE_COMPROBANTE_PPTAL.ANO,  
  PLAN_PRESUPUESTAL.ID,
  CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='7'
         THEN 'DC'
         ELSE ''
         END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='8'
       THEN 'DA'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='10'
       THEN 'E'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='11'
       THEN 'D'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='13'
       THEN 'RP'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='15'
       THEN 'OC'
       ELSE ''
       END CLASELETRAS, 
   DETALLE_COMPROBANTE_PPTAL.COMPROBANTE, 
   DETALLE_COMPROBANTE_PPTAL.CUENTA,  
   CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='8'
       THEN (DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO)*-1
       ELSE 0
       END DERECHOSANULADOS,
   CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='7'
       THEN ABS((DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO))
       ELSE 0
       END DERECHOSCAUSADOS,
   DETALLE_COMPROBANTE_PPTAL.DESCRIPCION,  
   CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='10'
       THEN ABS((DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO))
       ELSE 0
       END EFECTIVO,
  CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='11'
       THEN (DETALLE_COMPROBANTE_PPTAL.VALOR_CREDITO-DETALLE_COMPROBANTE_PPTAL.VALOR_DEBITO)*-1
       ELSE 0
       END DEVOLUCIONES,
  EXTRACT (DAY FROM DETALLE_COMPROBANTE_PPTAL.FECHA) DIA,    
  DETALLE_COMPROBANTE_PPTAL.FECHA      
FROM COMPROBANTE_PPTAL      
 INNER JOIN DETALLE_COMPROBANTE_PPTAL 
  ON  COMPROBANTE_PPTAL.COMPANIA = DETALLE_COMPROBANTE_PPTAL.COMPANIA
  AND COMPROBANTE_PPTAL.ANO      = DETALLE_COMPROBANTE_PPTAL.ANO
  AND COMPROBANTE_PPTAL.TIPO     = DETALLE_COMPROBANTE_PPTAL.TIPO_CPTE
  AND COMPROBANTE_PPTAL.NUMERO   = DETALLE_COMPROBANTE_PPTAL.COMPROBANTE 
 INNER JOIN V_PLAN_PRESUPUESTAL PLAN_PRESUPUESTAL
  ON  DETALLE_COMPROBANTE_PPTAL.COMPANIA = PLAN_PRESUPUESTAL.COMPANIA
  AND DETALLE_COMPROBANTE_PPTAL.ANO      = PLAN_PRESUPUESTAL.ANO
  AND DETALLE_COMPROBANTE_PPTAL.ID   = PLAN_PRESUPUESTAL.ID
 INNER JOIN TIPO_COMPROBPP
  ON  DETALLE_COMPROBANTE_PPTAL.COMPANIA   = TIPO_COMPROBPP.COMPANIA
  AND DETALLE_COMPROBANTE_PPTAL.TIPO_CPTE = TIPO_COMPROBPP.CODIGO
WHERE COMPROBANTE_PPTAL.COMPANIA    = s$compania$s 
  AND DETALLE_COMPROBANTE_PPTAL.ANO = s$anio$s 
  AND DETALLE_COMPROBANTE_PPTAL.MES BETWEEN s$mesInicial$s AND s$mesFinal$s 
  AND PLAN_PRESUPUESTAL.NATURALEZA  = 'C'
  AND LENGTH(DETALLE_COMPROBANTE_PPTAL.CUENTA) BETWEEN 0 AND s$nivel$s 
  AND PLAN_PRESUPUESTAL.CODIGO BETWEEN 's$cuentaInicial$s' 
                                   AND 's$cuentaFinal$s' 
  s$condFuenteRecurso$s  
  s$condCentroCosto$s  
  AND (
    CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='7'
         THEN 'DC'
         ELSE ''
         END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='8'
       THEN 'DA'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='10'
       THEN 'E'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='11'
       THEN 'D'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='13'
       THEN 'RP'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='15'
       THEN 'OC'
       ELSE ''
       END) IS NOT NULL
